    }
}

fn main() {
    // for with range
    for i in 1..=3 {
        println!("i = {}", i);
    }

    // while
    let mut n = 3;
    while n > 0 {
        println!("n = {}", n);
        n -= 1;
    }

    // loop with break value
    let result = loop {
        break 42;
    };
    println!("result = {}", result);
}

