fn length(s: &String) -> usize {
    s.len()
}

fn append(s: &mut String) {
    s.push_str(" world");
}

fn main() {
    let s = String::from("hello");
    let len = length(&s);
    println!("len = {}", len);

    let mut s2 = String::from("hello");
    append(&mut s2);
    println!("{}", s2);
}

struct Rectangle {
    width: f64,
    height: f64,
}

impl Rectangle {
    fn area(&self) -> f64 {
        self.width * self.height
    }
    fn new(w: f64, h: f64) -> Rectangle {
        Rectangle { width: w, height: h }
    }
}

fn main() {
    let r = Rectangle::new(4.0, 3.0);
    println!("Area = {}", r.area());
}

enum Direction {
    North,
    South,
    East,
    West,
}

fn describe(d: Direction) {
    match d {
        Direction::North => println!("Going north"),
        Direction::South => println!("Going south"),
        Direction::East  => println!("Going east"),
        Direction::West  => println!("Going west"),
    }
}

fn main() {
    describe(Direction::North);
    let maybe: Option<i32> = Some(42);
    if let Some(v) = maybe {
        println!("Got {}", v);
    }
}

fn categorise(n: i32) -> &'static str {
    match n {
        i32::MIN..=-1 => "negative",
        0             => "zero",
        1..=9         => "single digit",
        _             => "large",
    }
}

fn main() {
    for n in [-5, 0, 7, 42] {
        println!("{} is {}", n, categorise(n));
    }

    let pair = (1, -1);
    match pair {
        (x, y) if x == y => println!("equal"),
        (x, y) if x + y == 0 => println!("opposites"),
        _ => println!("other"),
    }
}

